import { CCol, CForm, CFormInput, CContainer, CRow, CFormLabel, CButton } from '@coreui/react';
import React, { useState } from 'react';
import TextArea from '../common/TextArea';

const MagazineComponent = () => {
    const [formData, setFormData] = useState({ title: '', article: '', file: null, encodedFileData: "", fileName: "", metadata: {} });


    const handleChange = (e) => {
        const { name, value, files } = e.target;

        if (name === 'file') {
            let selectedFile = files[0];
            let fileName = e.target.files[0].name;
            setFormData({ ...formData, [name]: selectedFile, fileName: fileName });

            let reader = new FileReader();
            reader.onloadend = () => {

                /* convert Base64 string */
                let base64String = reader.result.split(',')[1];
                console.log("Base64String:", base64String);

                /* Format it for Binary.createFromBase64 */
                let binaryData = `Binary.createFromBase64('${base64String}', 0)`;
                console.log("BinaryData:", binaryData);
                // setFormData((prevData) => ({ ...prevData, encodedFileData: binaryData }));

                // Extract image metadata
                const img = new Image();
                img.onload = () => {
                    const metadata = {
                        width: img.width,
                        height: img.height,
                        aspect_ratio: img.width / img.height,
                    };

                    // Update formData with binary data and metadata
                    setFormData((prevData) => ({ ...prevData, encodedFileData: binaryData, metadata: metadata }));

                    console.log("Metadata:", metadata);
                };
                img.src = event.target.result;


            };
            reader.readAsDataURL(selectedFile);
        } else {
            setFormData({ ...formData, [name]: value });
        }
    };


    const handleSubmit = (e) => {
        e.preventDefault();


        let postData = {
            filename: formData?.fileName,
            title: formData?.title,
            image_data: formData?.encodedFileData,
            metadata: { width: 275, height: 183, aspect_ratio: 1.5027322404371584 },
        }

        console.log('postData:', postData);
    };

    return (
        <CContainer className="d-flex justify-content-center align-items-center" style={{ minHeight: '50vh' }}>
            <CRow className="w-90">
                <CCol md={12}>
                    <CFormLabel htmlFor="formFile">Title<span className="text-danger">*</span></CFormLabel>
                    <CForm>
                        <CFormInput
                            id="exampleFormControlInput1"
                            placeholder="Enter title"
                            name="title"
                            value={formData?.title}
                            onChange={(e) => { handleChange(e) }}
                        />
                    </CForm>
                </CCol>
                <CCol md={12}>
                    <TextArea
                        value={formData?.article}
                        label="Article"
                        required
                        name="article"
                        onChange={(e) => { handleChange(e) }}
                        placeholder="Write your article here"
                    />
                </CCol>
                <CCol md={12}>
                    <div>
                        <CFormInput
                            type="file"
                            size="lg"
                            id="formFileLg"
                            label="Large file input example"
                            name="file"
                            onChange={(e) => { handleChange(e) }}
                        />
                    </div>
                </CCol>
                <CCol md={12} className="mt-3">
                    <CButton color="primary" onClick={handleSubmit}> Submit </CButton>
                </CCol>
            </CRow>
        </CContainer>
    );
};

export default MagazineComponent;
